# ── ESTILOS EXCEL ──────────────────────────────────────────────────────────────
AZUL_OSC="1F3864"; AZUL_MED="2E75B6"; AZUL_CLR="DDEBF7"; ROJO_HDR="C00000"
ROJO_CLR="FCE4D6"; ROJO_ALT="F8CBAD"; VERDE_HDR="375623"; VERDE_CLR="E2EFDA"
VERDE_ALT="C6E0B4"; AMAR_CLR="FFF2CC"; GRIS_CLR="F2F2F2"; BLANCO="FFFFFF"; NEGRO="000000"
thin=Side(style="thin",color="BFBFBF"); brd=Border(left=thin,right=thin,top=thin,bottom=thin)
def fill(h): return PatternFill("solid",fgColor=h)
def font(bold=False,color=NEGRO,sz=10): return Font(name="Arial",bold=bold,size=sz,color=color)
def alig(h="left",wrap=True): return Alignment(horizontal=h,vertical="center",wrap_text=wrap)
def set_col_width(ws,col,w): ws.column_dimensions[get_column_letter(col)].width=w
def write_header(ws,row,col,value,bg,fg=BLANCO,sz=10,bold=True,h="center"):
    c=ws.cell(row=row,column=col,value=value); c.font=font(bold=bold,color=fg,sz=sz)
    c.fill=fill(bg); c.border=brd; c.alignment=alig(h); return c
def write_cell(ws,row,col,value,bg=BLANCO,fg=NEGRO,bold=False,sz=9,h="left",num_fmt=None):
    c=ws.cell(row=row,column=col,value=value); c.font=font(bold=bold,color=fg,sz=sz)
    c.fill=fill(bg); c.border=brd; c.alignment=alig(h)
    if num_fmt: c.number_format=num_fmt
    return c

# ── CONFIGURACION ──────────────────────────────────────────────────────────────
MAPA_COLUMNAS={"Material":["Material","material","Codigo","Código"],"Descripcion":["Descripcion","Descripción","descripcion"],"Categoria":["Categoria","Categoría","categoria","Familia"],"Diferencia":["Diferencia","diferencia","Cant. Dif"],"Costo_Unitario":["Costo Unitario","Costo_Unitario","costo unitario","Precio U"],"Costo_Total":["Costo Total","Costo_Total","costo total","Subtotal"]}
STOPWORDS={"DE","PARA","CON","EL","LA","UN","EN","DEL","LOS","LAS","PZ","MZ","Y","A","AL","KG","MTS","PZA","X"}

def resolver_columnas(df_cols):
    r={}
    for ni,vs in MAPA_COLUMNAS.items():
        f=next((v for v in vs if v in df_cols),None); r[ni]=f
    return r

def obtener_palabras(texto):
    if pd.isna(texto) or str(texto).strip()=="": return set()
    txt=re.sub(r"[/-_]"," ",str(texto).upper()); txt=re.sub(r"[^A-Z0-9\s]","",txt)
    return {p for p in txt.split() if len(p)>2 and p not in STOPWORDS and sum(1 for c in p if c.isdigit())/len(p)<=0.5}

def jaccard(s1,s2):
    if not s1 or not s2: return 0.0
    return len(s1&s2)/len(s1|s2)

def nivel_confianza(sim,am,mm):
    if sim>=am: return ("ALTA","🟢",VERDE_CLR)
    if sim>=mm: return ("MEDIA","🟡",AMAR_CLR)
    return ("BAJA","🔴",ROJO_CLR)

def cargar_configuracion(fb):
    cfg={"TOLERANCIA_COSTO":.05,"UMBRAL_JACCARD":.30,"ALTA_MIN":.70,"MEDIA_MIN":.45,"FILTRAR_CATEGORIA":True,"GENERAR_DIAG":False,"nombre_tienda":"","centro_sap":"","fecha_inventario":""}
    try:
        df=pd.read_excel(fb,sheet_name="Configuracion",header=None); raw={}
        for _,row in df.iterrows():
            if pd.notna(row.iloc[0]) and pd.notna(row.iloc[1]): raw[str(row.iloc[0]).strip()]=row.iloc[1]
        if "Tolerancia Costo %" in raw: cfg["TOLERANCIA_COSTO"]=float(raw["Tolerancia Costo %"])/100
        if "Umbral Similitud %" in raw: cfg["UMBRAL_JACCARD"]=float(raw["Umbral Similitud %"])/100
        if "Umbral Confianza Alta %" in raw: cfg["ALTA_MIN"]=float(raw["Umbral Confianza Alta %"])/100
        if "Umbral Confianza Media %" in raw: cfg["MEDIA_MIN"]=float(raw["Umbral Confianza Media %"])/100
        if "Filtrar por Categoria" in raw: cfg["FILTRAR_CATEGORIA"]=str(raw["Filtrar por Categoria"]).strip().upper()=="SI"
        if "Generar Diagnostico" in raw: cfg["GENERAR_DIAG"]=str(raw["Generar Diagnostico"]).strip().upper()=="SI"
        if "Nombre Tienda" in raw: cfg["nombre_tienda"]=str(raw["Nombre Tienda"]).strip()
        if "Centro SAP" in raw: cfg["centro_sap"]=str(raw["Centro SAP"]).strip()
        if "Fecha Inventario" in raw: cfg["fecha_inventario"]=str(raw["Fecha Inventario"]).strip()
    except Exception: pass
    return cfg

def cargar_datos(fb):
    df=pd.read_excel(fb,sheet_name="Diferencias",header=1,dtype={"Material":str})
    mapa=resolver_columnas(df.columns.tolist())
    miss=[k for k in ["Material","Descripcion","Diferencia","Costo_Unitario","Costo_Total"] if mapa[k] is None]
    if miss: raise ValueError(f"Columnas no encontradas: {miss}\nColumnas en archivo: {df.columns.tolist()}")
    df=df.rename(columns={v:k for k,v in mapa.items() if v is not None})
    if "Categoria" not in df.columns: df["Categoria"]=""
    df=df[df["Diferencia"]!=0].copy()
    for col in ["Diferencia","Costo_Unitario","Costo_Total"]: df[col]=pd.to_numeric(df[col],errors="coerce").fillna(0)
    df["Categoria"]=df["Categoria"].fillna("").astype(str).str.strip()
    return df

def ejecutar_cruces(df,cfg,pb,st_):
    TC=cfg["TOLERANCIA_COSTO"]; UJ=cfg["UMBRAL_JACCARD"]; AM=cfg["ALTA_MIN"]; MM=cfg["MEDIA_MIN"]; FC=cfg["FILTRAR_CATEGORIA"]
    falt=df[df["Diferencia"]<0].copy().reset_index(drop=True)
    sobr=df[df["Diferencia"]>0].copy().reset_index(drop=True)
    falt["Saldo"]=falt["Diferencia"].abs(); sobr["Saldo"]=sobr["Diferencia"].abs()
    falt["Palabras"]=falt["Descripcion"].apply(obtener_palabras)
    sobr["Palabras"]=sobr["Descripcion"].apply(obtener_palabras)
    sc=sobr["Costo_Unitario"].values; ss=sc.argsort(); scs=sc[ss]
    af={i:0.0 for i in range(len(falt))}; as_={i:0.0 for i in range(len(sobr))}
    cruces=[]; cnt=0; tf=len(falt)
    st_.markdown('<div style="font-family:Montserrat;font-size:13px;color:#0d2c6b;font-weight:600;">⚙️ Pasada 1 — cruzando con validación de costo...</div>',unsafe_allow_html=True)
    for if_ in range(tf):
        if falt.at[if_,"Saldo"]<=0: continue
        pb.progress((if_+1)/tf*.5,text=f"Pasada 1: {if_+1}/{tf} | Cruces: {cnt}")
        cf=falt.at[if_,"Costo_Unitario"]; li=cf*(1-TC); ls=cf*(1+TC)
        pf=falt.at[if_,"Palabras"]; catf=falt.at[if_,"Categoria"]
        matf=falt.at[if_,"Material"]; descf=falt.at[if_,"Descripcion"]
        cands=[]
        for is_ in ss[bisect.bisect_left(scs,li):bisect.bisect_right(scs,ls)]:
            if sobr.at[is_,"Saldo"]<=0: continue
            cs_=sobr.at[is_,"Costo_Unitario"]
            if not(li<=cs_<=ls): continue
            if FC:
                c1=catf.strip(); c2=sobr.at[is_,"Categoria"].strip()
                if c1 and c2 and c1.upper()!=c2.upper(): continue
            sim=jaccard(pf,sobr.at[is_,"Palabras"])
            if sim<UJ: continue
            cands.append((is_,sim))
        cands.sort(key=lambda x:x[1],reverse=True)
        for is_,sim in cands:
            if falt.at[if_,"Saldo"]<=0: break
            cant=min(falt.at[if_,"Saldo"],sobr.at[is_,"Saldo"])
            cu_s=sobr.at[is_,"Costo_Unitario"]; nv,em,_=nivel_confianza(sim,AM,MM); cnt+=1
            df_=-round(cant,2); ds_=round(cant,2); ctf=round(-cant*cf,2); cts=round(cant*cu_s,2)
            ps=sobr.at[is_,"Palabras"]; af[if_]+=cant; as_[is_]+=cant
            cruces.append({"No_Cruce":cnt,"Confianza":em+" "+nv,"Similitud":round(sim*100,1),
                "Comunes":", ".join(sorted(pf&ps)),"Unicas":", ".join(sorted(pf|ps)),
                "Mat_F":matf,"Desc_F":descf,"Cat_F":catf,"Dif_F":df_,"CostoU_F":cf,"CostoT_F":ctf,
                "Cantidad_Cruce":cant,"Mat_S":sobr.at[is_,"Material"],"Desc_S":sobr.at[is_,"Descripcion"],
                "Cat_S":sobr.at[is_,"Categoria"],"Dif_S":ds_,"CostoU_S":cu_s,"CostoT_S":cts,
                "Dif_Cantidad":round(df_+ds_,2),"Dif_Costo":round(ctf+cts,2)})
            falt.at[if_,"Saldo"]-=cant; sobr.at[is_,"Saldo"]-=cant
    st_.markdown('<div style="font-family:Montserrat;font-size:13px;color:#0d2c6b;font-weight:600;">⚙️ Pasada 2 — cruzando sin validación de costo...</div>',unsafe_allow_html=True)
    cruces_sc=[]; cnt_sc=0; tf2=sum(1 for i in range(len(falt)) if falt.at[i,"Saldo"]>0); p2=0
    for if_ in range(len(falt)):
        if falt.at[if_,"Saldo"]<=0: continue
        p2+=1; pb.progress(.5+(p2/max(tf2,1))*.4,text=f"Pasada 2: {p2}/{tf2} | Cruces sin costo: {cnt_sc}")
        cf=falt.at[if_,"Costo_Unitario"]; pf=falt.at[if_,"Palabras"]
        catf=falt.at[if_,"Categoria"]; matf=falt.at[if_,"Material"]; descf=falt.at[if_,"Descripcion"]
        cands2=[]
        for is_ in range(len(sobr)):
            if sobr.at[is_,"Saldo"]<=0: continue
            if FC:
                c1=catf.strip(); c2=sobr.at[is_,"Categoria"].strip()
                if c1 and c2 and c1.upper()!=c2.upper(): continue
            sim=jaccard(pf,sobr.at[is_,"Palabras"])
            if sim<UJ: continue
            cands2.append((is_,sim))
        cands2.sort(key=lambda x:x[1],reverse=True)
        for is_,sim in cands2:
            if falt.at[if_,"Saldo"]<=0: break
            cant=min(falt.at[if_,"Saldo"],sobr.at[is_,"Saldo"])
            cu_s=sobr.at[is_,"Costo_Unitario"]; nv,em,_=nivel_confianza(sim,AM,MM); cnt_sc+=1
            df_=-round(cant,2); ds_=round(cant,2); ctf=round(-cant*cf,2); cts=round(cant*cu_s,2)
            dp=round(abs(cf-cu_s)/(cf or 1)*100,1); ps=sobr.at[is_,"Palabras"]
            af[if_]+=cant; as_[is_]+=cant
            cruces_sc.append({"No_Cruce":cnt_sc,"Confianza":em+" "+nv,"Similitud":round(sim*100,1),
                "Comunes":", ".join(sorted(pf&ps)),"Unicas":", ".join(sorted(pf|ps)),
                "Mat_F":matf,"Desc_F":descf,"Cat_F":catf,"Dif_F":df_,"CostoU_F":cf,"CostoT_F":ctf,
                "Cantidad_Cruce":cant,"Mat_S":sobr.at[is_,"Material"],"Desc_S":sobr.at[is_,"Descripcion"],
                "Cat_S":sobr.at[is_,"Categoria"],"Dif_S":ds_,"CostoU_S":cu_s,"CostoT_S":cts,
                "Dif_Cantidad":round(df_+ds_,2),"Dif_Costo":round(ctf+cts,2),"Dif_Costo_Pct":dp})
            falt.at[if_,"Saldo"]-=cant; sobr.at[is_,"Saldo"]-=cant
    nc=[]
    for i in range(len(falt)):
        sr=falt.at[i,"Saldo"]
        if sr>0:
            row=falt.iloc[i]; nc.append({"Material":row["Material"],"Descripcion":row["Descripcion"],"Categoria":row["Categoria"],"Diferencia":row["Diferencia"],"Costo_Unitario":row["Costo_Unitario"],"Costo_Total":row["Costo_Total"],"Tipo":"Faltante","Cantidad_Disponible":round(-sr,2)})
    for i in range(len(sobr)):
        sr=sobr.at[i,"Saldo"]
        if sr>0:
            row=sobr.iloc[i]; nc.append({"Material":row["Material"],"Descripcion":row["Descripcion"],"Categoria":row["Categoria"],"Diferencia":row["Diferencia"],"Costo_Unitario":row["Costo_Unitario"],"Costo_Total":row["Costo_Total"],"Tipo":"Sobrante","Cantidad_Disponible":round(sr,2)})
    rf={falt.at[i,"Material"]:round(af[i],2) for i in range(len(falt))}
    rs={sobr.at[i,"Material"]:round(as_[i],2) for i in range(len(sobr))}
    pb.progress(.92,text="📊 Generando reporte Excel...")
    return pd.DataFrame(cruces),pd.DataFrame(cruces_sc),pd.DataFrame(nc),rf,rs

