    r+=1; rt(r,"VALOR CRUZADO"); r+=1
    rf_(r,"Valor faltante cruzado",vcf,bv=ROJO_CLR,nf="#,##0.00",bv_=True); r+=1
    rf_(r,"Valor sobrante cruzado",vcs,bv=VERDE_CLR,nf="#,##0.00",bv_=True); r+=1
    rf_(r,"Diferencia neta",round(vcf+vcs,2),bv=AZUL_CLR,nf="#,##0.00",bv_=True); r+=1
