def generar_plantilla():
    wb=openpyxl.Workbook(); ws=wb.active; ws.title="Diferencias"; ws.sheet_view.showGridLines=False
    ws.row_dimensions[1].height=30; ws.row_dimensions[2].height=20; ws.merge_cells("A1:F1")
    write_header(ws,1,1,"CONTRALORIA GO CORP — DIFERENCIAS DE INVENTARIO",AZUL_OSC,sz=12)
    for i,h in enumerate(["Material","Descripción","Categoría","Diferencia","Costo Unitario","Costo Total"],1): write_header(ws,2,i,h,AZUL_MED)
    for i,w in enumerate([18,45,18,14,16,16],1): set_col_width(ws,i,w)
    ws.freeze_panes="A3"
    wc=wb.create_sheet("Configuracion"); wc.sheet_view.showGridLines=False
    set_col_width(wc,1,30); set_col_width(wc,2,12); set_col_width(wc,3,45); set_col_width(wc,4,55)
    wc.row_dimensions[1].height=25; wc.merge_cells("A1:D1")
    c=wc.cell(row=1,column=1,value="DATOS DEL INVENTARIO"); c.font=font(bold=True,color=BLANCO,sz=11); c.fill=fill(AZUL_OSC); c.alignment=alig("center"); c.border=brd
    for i,(p,v,d) in enumerate([("Nombre Tienda","","Nombre de la tienda auditada"),("Centro SAP","","Codigo del centro en SAP"),("Fecha Inventario","","Fecha de toma de inventario (DD/MM/AAAA)")],start=2):
        wc.row_dimensions[i].height=18
        for col,vv,bg in[(1,p,GRIS_CLR),(2,v,AMAR_CLR),(3,d,BLANCO)]:
            cx=wc.cell(row=i,column=col,value=vv); cx.font=font(bold=(col==1),sz=10 if col<3 else 9,color="595959" if col==3 else NEGRO); cx.fill=fill(bg); cx.border=brd; cx.alignment=alig("left")
        wc.merge_cells(start_row=i,start_column=3,end_row=i,end_column=4)
    wc.row_dimensions[5].height=8; wc.row_dimensions[6].height=25; wc.merge_cells("A6:D6")
    c=wc.cell(row=6,column=1,value="PARAMETROS DE CALCULO"); c.font=font(bold=True,color=BLANCO,sz=11); c.fill=fill(AZUL_OSC); c.alignment=alig("center"); c.border=brd
    wc.row_dimensions[7].height=20
    for i,h in enumerate(["Parámetro","Valor","Descripción","Interpretación"],1):
        cx=wc.cell(row=7,column=i,value=h); cx.font=font(bold=True,color=BLANCO,sz=10); cx.fill=fill(AZUL_MED); cx.border=brd; cx.alignment=alig("center")
    params=[("Tolerancia Costo %",5,"Variación máxima permitida entre costos unitarios","Un ítem de $100 acepta sobrantes entre $95 y $105"),("Umbral Similitud %",30,"Coincidencia mínima de palabras","De cada 10 palabras al menos 3 deben coincidir"),("Umbral Confianza Alta %",70,"Similitud desde la cual el cruce es 🟢 ALTA","7 de cada 10 palabras coinciden"),("Umbral Confianza Media %",45,"Similitud desde la cual el cruce es 🟡 MEDIA","Entre 4 y 7 palabras coinciden"),("Filtrar por Categoria","SI","Faltante y sobrante deben coincidir en categoría","SI = BICICLETA solo cruza con BICICLETA"),("Generar Diagnostico","NO","Genera diagnóstico con el detalle de cada decisión","SI = más lento pero permite investigar resultados")]
    for i,(p,v,d,t) in enumerate(params):
        r=8+i; wc.row_dimensions[r].height=30; alt=i%2==0; bg=GRIS_CLR if alt else BLANCO
        for col,vv,bg_,fnt in[(1,p,bg,font(bold=True,sz=10)),(2,v,AMAR_CLR,font(bold=True,sz=11)),(3,d,bg,font(sz=9)),(4,t,bg,font(sz=9,color="375623"))]:
            cx=wc.cell(row=r,column=col,value=vv); cx.font=fnt; cx.fill=fill(bg_); cx.border=brd; cx.alignment=alig("center" if col==2 else "left")
    out=io.BytesIO(); wb.save(out); out.seek(0); return out

